import { mkdir, readFile, writeFile } from 'node:fs/promises';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const docsDir = path.resolve(__dirname, '..');
const repoRoot = path.resolve(docsDir, '..');
const readmePath = path.join(repoRoot, 'README.md');
const outputPath = path.join(docsDir, 'src', 'content', 'docs', 'getting-started.md');

const frontmatter = `---
title: Getting Started
description: Quick start guide for BlastShield sourced from the repository README.
---

<!-- This file is generated by docs/scripts/sync-readme-to-docs.mjs. -->

`;

const readme = await readFile(readmePath, 'utf8');
const readmeBody = readme.replace(/^# .*\n+/, '');

await mkdir(path.dirname(outputPath), { recursive: true });
await writeFile(outputPath, `${frontmatter}${readmeBody}`);
